t.script:
//
(function() {
    var planSelect  = document.getElementById('plan_select');
    var btnGenerate = document.getElementById('btn_generate');
    var btnExport   = document.getElementById('btn_export');
    var loading     = document.getElementById('loading');
    var errorBox    = document.getElementById('error_box');
    var errorText   = document.getElementById('error_text');
    var results     = document.getElementById('results');
    var noResults   = document.getElementById('no_results');
    var tableWrapper= document.getElementById('table_wrapper');
    var tbody       = document.getElementById('report_tbody');
    var currentData = null;

    planSelect.addEventListener('change', function() {
        btnGenerate.disabled = !planSelect.value;
        hideResults();
    });

    btnGenerate.addEventListener('click', function() {
        if (!planSelect.value) return;
        loadData(planSelect.value);
    });

    btnExport.addEventListener('click', exportCSV);

    function loadData(planId) {
        showLoading();
        fetch('/purchase_plan_report/get_data', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({jsonrpc:'2.0', method:'call', params:{plan_id: planId}})
        })
        .then(function(r){ return r.json(); })
        .then(function(resp) {
            hideLoading();
            var data = resp.result;
            if (!data || data.error) {
                showError(data ? data.error : 'უცნობი შეცდომა');
                return;
            }
            currentData = data;
            renderResults(data);
        })
        .catch(function(e) {
            hideLoading();
            showError('კავშირის შეცდომა: ' + e.message);
        });
    }

    function renderResults(data) {
        document.getElementById('sum_plan_name').textContent = data.plan_name;
        document.getElementById('sum_period').textContent    = data.start_date + ' — ' + data.end_date;
        document.getElementById('sum_count').textContent     = data.total_lines;

        results.style.display = 'block';

        if (data.total_lines === 0) {
            noResults.style.display    = 'block';
            tableWrapper.style.display = 'none';
            btnExport.style.display    = 'none';
            return;
        }

        noResults.style.display    = 'none';
        tableWrapper.style.display = 'block';
        btnExport.style.display    = 'inline-block';
        btnExport.disabled         = false;

        tbody.innerHTML = '';
        var rowNum = 1;

        data.lines.forEach(function(line) {
            var negLines = line.negative_cpv_lines;
            var curr     = line.currency_symbol;

            negLines.forEach(function(cl, idx) {
                var tr = document.createElement('tr');

                // Plan line cells (only on first cpv-line row)
                if (idx === 0) {
                    tr.innerHTML =
                        '<td rowspan="' + negLines.length + '" class="align-middle font-weight-bold">' + rowNum + '</td>' +
                        '<td rowspan="' + negLines.length + '" class="align-middle text-info font-weight-bold">' + escHtml(line.cpv_code) + '</td>' +
                        '<td rowspan="' + negLines.length + '" class="align-middle">' + escHtml(line.cpv_name) + '</td>' +
                        '<td rowspan="' + negLines.length + '" class="align-middle">' + escHtml(line.funding_source) + '</td>' +
                        '<td rowspan="' + negLines.length + '" class="align-middle">' + escHtml(line.purchase_method) + '</td>' +
                        '<td rowspan="' + negLines.length + '" class="align-middle text-right font-weight-bold">' + fmt(line.pu_ac_am) + ' ' + curr + '</td>' +
                        cpvCells(cl);
                } else {
                    tr.innerHTML = cpvCells(cl);
                }
                tbody.appendChild(tr);
            });
            rowNum++;
        });
    }

    function cpvCells(cl) {
        var curr = cl.currency_symbol;
        var puReAmClass = cl.pu_re_am < 0 ? 'text-danger font-weight-bold' : 'text-success';
        return '<td>' + escHtml(cl.budget_line_name) + '</td>' +
               '<td>' + escHtml(cl.selected_plan_name) + '</td>' +
               '<td class="text-right">' + fmt(cl.budget_amount) + ' ' + curr + '</td>' +
               '<td class="text-right">' + fmt(cl.amount) + ' ' + curr + '</td>' +
               '<td class="text-right ' + puReAmClass + '">' + fmt(cl.pu_re_am) + ' ' + curr + '</td>';
    }

    function exportCSV() {
        if (!currentData) return;
        var rows = [['#','CPV კოდი','CPV დასახელება','დაფინანსება','მეთოდი','მიმდინ. ღირ.','ბიუჯეტის ხაზი','შერჩეული გეგმა','ბიუჯეტი','გამოყოფილი','pu_re_am']];
        var num = 1;
        currentData.lines.forEach(function(line) {
            line.negative_cpv_lines.forEach(function(cl, idx) {
                rows.push([
                    idx === 0 ? num : '',
                    idx === 0 ? line.cpv_code : '',
                    idx === 0 ? line.cpv_name : '',
                    idx === 0 ? line.funding_source : '',
                    idx === 0 ? line.purchase_method : '',
                    idx === 0 ? line.pu_ac_am : '',
                    cl.budget_line_name,
                    cl.selected_plan_name,
                    cl.budget_amount,
                    cl.amount,
                    cl.pu_re_am
                ]);
            });
            num++;
        });
        var csv = rows.map(function(r){ return r.map(function(c){ return '"'+String(c).replace(/"/g,'""')+'"'; }).join(','); }).join('\n');
        var blob = new Blob(['\uFEFF'+csv], {type:'text/csv;charset=utf-8;'});
        var url  = URL.createObjectURL(blob);
        var a    = document.createElement('a');
        a.href   = url;
        a.download = 'purchase_plan_negative_budget_' + currentData.plan_name.replace(/\s+/g,'_') + '.csv';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }

    function fmt(v) { return Number(v).toLocaleString('ka-GE', {minimumFractionDigits:2, maximumFractionDigits:2}); }
    function escHtml(s) { var d=document.createElement('div'); d.appendChild(document.createTextNode(s||'')); return d.innerHTML; }
    function showLoading()  { loading.style.display='block'; hideResults(); errorBox.style.display='none'; }
    function hideLoading()  { loading.style.display='none'; }
    function hideResults()  { results.style.display='none'; btnExport.style.display='none'; currentData=null; }
    function showError(msg) { errorText.textContent=msg; errorBox.style.display='block'; }
})();
//
